import React, { useState, useEffect } from 'react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, Cell, PieChart, Pie, RadialBarChart, RadialBar
} from 'recharts';

// ── Constants ─────────────────────────────────────────────────────────
const COLORS = {
  pass:    '#22c55e',
  partial: '#f59e0b',
  fail:    '#ef4444',
  error:   '#6366f1',
};

const DIFF_COLORS = {
  easy:    '#3b82f6',
  medium:  '#f59e0b',
  hard:    '#ef4444',
  extreme: '#a855f7',
};

// ── Fetch benchmark results from backend ──────────────────────────────
async function fetchResults() {
  const API_BASE = process.env.REACT_APP_API_URL || 'http://localhost:8000';
  const token = localStorage.getItem('token');
  const resp = await fetch(`${API_BASE}/benchmark/results`, {
    headers: token ? { Authorization: `Bearer ${token}` } : {},
  });
  if (!resp.ok) throw new Error('Could not load benchmark results');
  return resp.json();
}

// ── Accuracy gauge ────────────────────────────────────────────────────
function AccuracyGauge({ value }) {
  const color = value >= 70 ? '#22c55e' : value >= 40 ? '#f59e0b' : '#ef4444';
  const circumference = 2 * Math.PI * 54;
  const progress = (value / 100) * circumference * 0.75;

  return (
    <div style={{ textAlign: 'center', position: 'relative' }}>
      <svg width={140} height={120} viewBox="0 0 140 120">
        {/* Background arc */}
        <circle cx={70} cy={80} r={54}
          fill="none" stroke="#f3f4f6" strokeWidth={10}
          strokeDasharray={`${circumference * 0.75} ${circumference}`}
          strokeDashoffset={0} strokeLinecap="round"
          transform="rotate(-225 70 80)"
        />
        {/* Progress arc */}
        <circle cx={70} cy={80} r={54}
          fill="none" stroke={color} strokeWidth={10}
          strokeDasharray={`${progress} ${circumference}`}
          strokeDashoffset={0} strokeLinecap="round"
          transform="rotate(-225 70 80)"
          style={{ transition: 'stroke-dasharray 1s ease' }}
        />
      </svg>
      <div style={{
        position: 'absolute', top: 45, left: 0, right: 0,
        textAlign: 'center',
      }}>
        <div style={{ fontSize: 32, fontWeight: 900, color, lineHeight: 1 }}>
          {value}%
        </div>
        <div style={{ fontSize: 11, color: '#9ca3af', marginTop: 2 }}>Accuracy</div>
      </div>
    </div>
  );
}

// ── Stat card ─────────────────────────────────────────────────────────
function StatCard({ icon, label, value, color, sub }) {
  return (
    <div style={{
      background: '#fff', borderRadius: 12, padding: '14px 16px',
      border: `1.5px solid ${color}20`,
      boxShadow: `0 2px 8px ${color}10`,
      display: 'flex', alignItems: 'center', gap: 12,
    }}>
      <div style={{
        width: 40, height: 40, borderRadius: 10,
        background: `${color}15`,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        fontSize: 18, flexShrink: 0,
      }}>
        {icon}
      </div>
      <div>
        <div style={{ fontSize: 22, fontWeight: 800, color, lineHeight: 1 }}>{value}</div>
        <div style={{ fontSize: 11, color: '#6b7280', marginTop: 2 }}>{label}</div>
        {sub && <div style={{ fontSize: 10, color: '#9ca3af' }}>{sub}</div>}
      </div>
    </div>
  );
}

// ── Difficulty row ────────────────────────────────────────────────────
function DifficultyBar({ difficulty, data }) {
  const color = DIFF_COLORS[difficulty] || '#6b7280';
  const acc   = data.accuracy || 0;

  return (
    <div style={{ marginBottom: 12 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{
            width: 8, height: 8, borderRadius: '50%', background: color,
          }}/>
          <span style={{ fontSize: 12, fontWeight: 600, color: '#374151',
            textTransform: 'capitalize' }}>
            {difficulty}
          </span>
          <span style={{ fontSize: 11, color: '#9ca3af' }}>
            ({data.total} tasks)
          </span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 11, color: '#6b7280' }}>
            {data.passed}✅ {data.partial}⚠️ {data.failed}❌ {data.errored}💥
          </span>
          <span style={{ fontSize: 13, fontWeight: 700, color }}>
            {acc.toFixed(1)}%
          </span>
        </div>
      </div>
      <div style={{ height: 8, background: '#f3f4f6', borderRadius: 4, overflow: 'hidden' }}>
        <div style={{
          height: '100%', width: `${acc}%`, background: color,
          borderRadius: 4, transition: 'width 0.8s ease',
        }}/>
      </div>
    </div>
  );
}

// ── Task row ──────────────────────────────────────────────────────────
function TaskRow({ result, index }) {
  const [expanded, setExpanded] = useState(false);
  const statusColor = {
    PASS:    '#22c55e', PARTIAL: '#f59e0b',
    FAIL:    '#ef4444', ERROR:   '#6366f1',
  }[result.status] || '#9ca3af';

  const statusBg = {
    PASS:    '#f0fdf4', PARTIAL: '#fffbeb',
    FAIL:    '#fef2f2', ERROR:   '#eef2ff',
  }[result.status] || '#f9fafb';

  const statusIcon = {
    PASS: '✅', PARTIAL: '⚠️', FAIL: '❌', ERROR: '💥',
  }[result.status] || '?';

  return (
    <div style={{
      border: `1px solid ${statusColor}20`,
      borderRadius: 10, overflow: 'hidden',
      marginBottom: 8, background: '#fff',
    }}>
      <div
        style={{
          display: 'flex', alignItems: 'center', gap: 12,
          padding: '10px 14px', cursor: 'pointer',
          background: expanded ? `${statusColor}05` : '#fff',
        }}
        onClick={() => setExpanded(e => !e)}
      >
        <span style={{ fontSize: 14, flexShrink: 0 }}>{statusIcon}</span>
        <div style={{
          flex: 1, fontSize: 12, color: '#374151',
          overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
        }}>
          <span style={{
            fontSize: 10, fontWeight: 700, color: DIFF_COLORS[result.difficulty],
            background: `${DIFF_COLORS[result.difficulty]}15`,
            borderRadius: 4, padding: '1px 5px', marginRight: 6,
            textTransform: 'uppercase',
          }}>
            {result.difficulty}
          </span>
          {result.question}
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}>
          {result.react_attempts > 1 && (
            <span style={{
              fontSize: 10, color: '#d97706', background: '#fffbeb',
              border: '1px solid #fcd34d', borderRadius: 4, padding: '1px 5px',
            }}>
              🔄 {result.react_attempts}x
            </span>
          )}
          <span style={{
            fontSize: 11, fontWeight: 700, color: statusColor,
            background: statusBg, borderRadius: 5, padding: '2px 8px',
          }}>
            {result.status}
          </span>
          <span style={{ fontSize: 12, color: statusColor === '#22c55e' ? '#9ca3af' : statusColor }}>
            {expanded ? '▲' : '▼'}
          </span>
        </div>
      </div>

      {expanded && (
        <div style={{ padding: '12px 14px', borderTop: `1px solid ${statusColor}15` }}>
          <div style={{ fontSize: 11, color: '#6b7280', marginBottom: 8 }}>
            {result.detail}
            {result.elapsed_s > 0 && ` · ${result.elapsed_s}s`}
          </div>

          {result.sql && (
            <pre style={{
              fontSize: 10, background: '#f8fafc', border: '1px solid #e2e8f0',
              borderRadius: 6, padding: '8px 10px', overflow: 'auto',
              whiteSpace: 'pre-wrap', margin: 0, fontFamily: 'monospace',
              color: '#1e1b4b', marginBottom: 8, maxHeight: 120,
            }}>
              {result.sql}
            </pre>
          )}

          {result.prediction?.length > 0 && result.gold?.length > 0 && (
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
              <div>
                <div style={{ fontSize: 10, fontWeight: 700, color: '#6b7280',
                  marginBottom: 4, textTransform: 'uppercase' }}>Got</div>
                <div style={{
                  fontSize: 11, background: statusBg, borderRadius: 6,
                  padding: '6px 8px', fontFamily: 'monospace',
                }}>
                  {JSON.stringify(result.prediction[0], null, 1)}
                </div>
              </div>
              <div>
                <div style={{ fontSize: 10, fontWeight: 700, color: '#6b7280',
                  marginBottom: 4, textTransform: 'uppercase' }}>Expected</div>
                <div style={{
                  fontSize: 11, background: '#f0fdf4', borderRadius: 6,
                  padding: '6px 8px', fontFamily: 'monospace',
                }}>
                  {JSON.stringify(result.gold[0], null, 1)}
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── Main Dashboard ────────────────────────────────────────────────────
export default function BenchmarkDashboard() {
  const [data, setData]       = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');
  const [filter, setFilter]   = useState('all');
  const [search, setSearch]   = useState('');
  const [diffFilter, setDiffFilter] = useState('all');

  useEffect(() => {
    fetchResults()
      .then(setData)
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center',
      height: '60vh', flexDirection: 'column', gap: 16 }}>
      <div style={{ fontSize: 32 }}>⚙️</div>
      <div style={{ fontSize: 14, color: '#6b7280' }}>Loading benchmark results...</div>
    </div>
  );

  if (error) return (
    <div style={{ padding: 40, textAlign: 'center' }}>
      <div style={{ fontSize: 32, marginBottom: 12 }}>📊</div>
      <div style={{ fontSize: 14, color: '#374151', fontWeight: 600, marginBottom: 8 }}>
        No benchmark results yet
      </div>
      <div style={{ fontSize: 12, color: '#9ca3af', maxWidth: 400, margin: '0 auto' }}>
        Run the benchmark first:
        <pre style={{ background: '#f3f4f6', borderRadius: 6, padding: '8px 12px',
          marginTop: 8, fontSize: 11, textAlign: 'left' }}>
          python benchmark_agent.py --limit 52
        </pre>
      </div>
    </div>
  );

  if (!data) return null;

  const { total, passed, partial, failed, errored, accuracy, by_difficulty, results } = data;

  // Chart data
  const statusData = [
    { name: 'Pass',    value: passed,  color: COLORS.pass    },
    { name: 'Partial', value: partial, color: COLORS.partial },
    { name: 'Fail',    value: failed,  color: COLORS.fail    },
    { name: 'Error',   value: errored, color: COLORS.error   },
  ].filter(d => d.value > 0);

  const diffData = Object.entries(by_difficulty).map(([diff, d]) => ({
    name: diff.charAt(0).toUpperCase() + diff.slice(1),
    accuracy: d.accuracy,
    passed: d.passed,
    partial: d.partial,
    failed: d.failed,
    errored: d.errored,
    color: DIFF_COLORS[diff],
  }));

  // Self-correction stats
  const selfCorrected = results.filter(r => r.self_corrected).length;
  const avgTime       = results.length
    ? (results.reduce((a, r) => a + (r.elapsed_s || 0), 0) / results.length).toFixed(1)
    : 0;

  // Filtered results
  const filteredResults = results.filter(r => {
    const matchStatus = filter === 'all' || r.status === filter.toUpperCase();
    const matchDiff   = diffFilter === 'all' || r.difficulty === diffFilter;
    const matchSearch = !search || r.question.toLowerCase().includes(search.toLowerCase());
    return matchStatus && matchDiff && matchSearch;
  });

  return (
    <div style={{ padding: '20px 24px', display: 'flex', flexDirection: 'column', gap: 20 }}>

      {/* Header */}
      <div style={{
        background: 'linear-gradient(135deg, #1e1b4b, #312e81)',
        borderRadius: 14, padding: '20px 24px',
        display: 'flex', alignItems: 'center', gap: 20,
        color: '#fff',
      }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 10, fontWeight: 700, color: '#a5b4fc',
            textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: 6 }}>
            KDD Cup 2026 DataAgent-Bench Phase 1
          </div>
          <div style={{ fontSize: 20, fontWeight: 800, marginBottom: 4 }}>
            Database Assistant Benchmark
          </div>
          <div style={{ fontSize: 12, color: '#c7d2fe' }}>
            SJSU CMPE 295B Master's Project · {total} tasks evaluated
          </div>
        </div>
        <AccuracyGauge value={accuracy}/>
      </div>

      {/* Stats row */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 10 }}>
        <StatCard icon="✅" label="Passed" value={passed}
          color="#22c55e" sub={`${(passed/total*100).toFixed(1)}%`}/>
        <StatCard icon="⚠️" label="Partial" value={partial}
          color="#f59e0b" sub={`${(partial/total*100).toFixed(1)}%`}/>
        <StatCard icon="🔄" label="Self-Corrected" value={selfCorrected}
          color="#6366f1" sub="ReAct loop fixed these"/>
        <StatCard icon="⏱" label="Avg Time" value={`${avgTime}s`}
          color="#0891b2" sub="per task"/>
      </div>

      {/* Charts row */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.6fr', gap: 16 }}>

        {/* Pie chart */}
        <div style={{
          background: '#fff', borderRadius: 12, padding: '16px',
          border: '1.5px solid #e5e7eb',
        }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: '#374151',
            textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 14 }}>
            Result Breakdown
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            <ResponsiveContainer width={140} height={140}>
              <PieChart>
                <Pie data={statusData} dataKey="value" cx="50%" cy="50%"
                  innerRadius={40} outerRadius={65} paddingAngle={3}>
                  {statusData.map((entry, i) => (
                    <Cell key={i} fill={entry.color} stroke="white" strokeWidth={2}/>
                  ))}
                </Pie>
                <Tooltip formatter={(v, n) => [`${v} tasks`, n]}
                  contentStyle={{ borderRadius: 8, fontSize: 12 }}/>
              </PieChart>
            </ResponsiveContainer>
            <div style={{ flex: 1 }}>
              {statusData.map(s => (
                <div key={s.name} style={{ display: 'flex', alignItems: 'center',
                  gap: 8, marginBottom: 8 }}>
                  <div style={{ width: 10, height: 10, borderRadius: 2,
                    background: s.color, flexShrink: 0 }}/>
                  <div style={{ flex: 1, fontSize: 12, color: '#374151' }}>{s.name}</div>
                  <div style={{ fontSize: 12, fontWeight: 700, color: s.color }}>
                    {s.value}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Bar chart by difficulty */}
        <div style={{
          background: '#fff', borderRadius: 12, padding: '16px',
          border: '1.5px solid #e5e7eb',
        }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: '#374151',
            textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 14 }}>
            Accuracy by Difficulty
          </div>
          <ResponsiveContainer width="100%" height={140}>
            <BarChart data={diffData} margin={{ top: 5, right: 10, left: -10, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="#f1f3f7" vertical={false}/>
              <XAxis dataKey="name" tick={{ fontSize: 11, fill: '#6b7591' }}
                axisLine={false} tickLine={false}/>
              <YAxis tick={{ fontSize: 10, fill: '#6b7591' }} axisLine={false}
                tickLine={false} tickFormatter={v => `${v}%`} domain={[0, 100]}/>
              <Tooltip formatter={v => [`${v}%`, 'Accuracy']}
                contentStyle={{ borderRadius: 8, fontSize: 12 }}/>
              <Bar dataKey="accuracy" radius={[6, 6, 0, 0]} maxBarSize={48}>
                {diffData.map((entry, i) => (
                  <Cell key={i} fill={entry.color}/>
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Difficulty breakdown */}
      <div style={{
        background: '#fff', borderRadius: 12, padding: '16px 18px',
        border: '1.5px solid #e5e7eb',
      }}>
        <div style={{ fontSize: 11, fontWeight: 700, color: '#374151',
          textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 14 }}>
          Accuracy by Difficulty Level
        </div>
        {Object.entries(by_difficulty).map(([diff, d]) => (
          <DifficultyBar key={diff} difficulty={diff} data={d}/>
        ))}
      </div>

      {/* Task results table */}
      <div style={{
        background: '#fff', borderRadius: 12, padding: '16px 18px',
        border: '1.5px solid #e5e7eb',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 14,
          flexWrap: 'wrap' }}>
          <div style={{ fontSize: 11, fontWeight: 700, color: '#374151',
            textTransform: 'uppercase', letterSpacing: '0.06em' }}>
            Individual Task Results
          </div>

          {/* Search */}
          <input
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search questions..."
            style={{
              fontSize: 12, padding: '5px 10px', borderRadius: 7,
              border: '1px solid #e5e7eb', outline: 'none',
              flex: 1, minWidth: 160,
            }}
          />

          {/* Status filter */}
          <div style={{ display: 'flex', gap: 4 }}>
            {['all', 'pass', 'partial', 'fail', 'error'].map(f => (
              <button key={f} onClick={() => setFilter(f)} style={{
                fontSize: 10, fontWeight: 600, padding: '4px 8px',
                borderRadius: 5, border: '1px solid',
                cursor: 'pointer',
                borderColor: filter === f ? '#6366f1' : '#e5e7eb',
                background: filter === f ? '#eef2ff' : '#fff',
                color: filter === f ? '#6366f1' : '#6b7280',
                textTransform: 'uppercase',
              }}>
                {f}
              </button>
            ))}
          </div>

          {/* Difficulty filter */}
          <div style={{ display: 'flex', gap: 4 }}>
            {['all', 'easy', 'medium', 'hard', 'extreme'].map(d => (
              <button key={d} onClick={() => setDiffFilter(d)} style={{
                fontSize: 10, fontWeight: 600, padding: '4px 8px',
                borderRadius: 5, border: '1px solid',
                cursor: 'pointer',
                borderColor: diffFilter === d ? DIFF_COLORS[d] || '#6366f1' : '#e5e7eb',
                background: diffFilter === d ? `${DIFF_COLORS[d] || '#6366f1'}15` : '#fff',
                color: diffFilter === d ? DIFF_COLORS[d] || '#6366f1' : '#6b7280',
                textTransform: 'uppercase',
              }}>
                {d}
              </button>
            ))}
          </div>

          <span style={{ fontSize: 11, color: '#9ca3af', marginLeft: 'auto' }}>
            {filteredResults.length} of {total} tasks
          </span>
        </div>

        <div style={{ maxHeight: 500, overflowY: 'auto' }}>
          {filteredResults.map((r, i) => (
            <TaskRow key={r.task_id} result={r} index={i}/>
          ))}
          {filteredResults.length === 0 && (
            <div style={{ textAlign: 'center', padding: '24px', color: '#9ca3af',
              fontSize: 13 }}>
              No tasks match the current filter
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
